// Build templates[] for the CRM. Always returns one item even if the sheet is empty.
const rows = $input.all().map(i => i.json || {});
const templates = rows
  .filter(r => String(r.deleted || '').toLowerCase() !== 'true')
  .map(r => ({ id: String(r.id || ''), name: r.name || '', body: r.body || '' }))
  .filter(r => r.id);
return [{ json: { templates } }];

// Expand incoming templates[] into one row each (incl. soft-deleted, so deletes mirror to the sheet).
const body = ($input.first().json || {}).body || {};
const tpls = Array.isArray(body.templates) ? body.templates : [];
return tpls.map(tp => ({ json: {
  id: String(tp.id || ''),
  name: tp.name || '',
  body: tp.body || '',
  deleted: tp.deleted ? 'true' : ''
}})).filter(i => i.json.id);
